contracts/SC1_IdentityRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// ============================================================
//  SC-1 · Identity Registry
//  DCBA — Dual-Chain Blockchain Architecture
// ============================================================
//
//  PURPOSE:
//  This is the "who is who" contract for the whole system.
//  Before any actor (patient, doctor, UAV, warehouse, etc.)
//  can do anything, they must be registered here by the TA
//  (Trusted Authority). Think of it like an ID card issuer.
//
//  ACTORS WHO USE THIS:
//  - TA (Trusted Authority) → registers and revokes everyone
//  - All other contracts    → call isActive() to check IDs
//
//  DEPLOY FIRST. All other contracts depend on this one.
// ============================================================

contract SC1_IdentityRegistry {

    // ── Role labels (just for readability) ──────────────────
    // We store these as plain strings so anyone reading the
    // blockchain can understand who is who.
    // Examples: "patient", "hp", "uav", "warehouse",
    //           "dronestation", "auditor", "miner"

    // ── What we store for each registered actor ──────────────
    struct Actor {
        string  role;           // e.g. "patient" or "uav"
        string  publicKeyHash;  // hash of their public key (DID)
        bool    isActive;       // true = valid, false = revoked
        uint256 registeredAt;   // when they were registered
    }

    // ── Storage ──────────────────────────────────────────────
    address public trustedAuthority;  // the TA who runs this contract

    // address → their Actor info
    mapping(address => Actor) public actors;

    // ── Events (logged on blockchain, useful for debugging) ──
    event ActorRegistered(address indexed who, string role, string publicKeyHash);
    event ActorRevoked(address indexed who, string reason);

    // ── Setup ─────────────────────────────────────────────────
    // The person who deploys this contract becomes the TA.
    constructor() {
        trustedAuthority = msg.sender;
    }

    // ── Modifier: only the TA can call certain functions ─────
    modifier onlyTA() {
        require(msg.sender == trustedAuthority, "Only TA can do this");
        _;
    }

    // ============================================================
    //  FUNCTION: register
    //  Who calls it: TA
    //  What it does: Adds a new actor to the system
    // ============================================================
    function register(
        address who,           // the actor's wallet address
        string memory role,    // their role: "patient", "hp", etc.
        string memory pubKeyHash  // hash of their public key
    ) public onlyTA {
        require(who != address(0), "Invalid address");
        require(!actors[who].isActive, "Already registered and active");

        actors[who] = Actor({
            role:          role,
            publicKeyHash: pubKeyHash,
            isActive:      true,
            registeredAt:  block.timestamp
        });

        emit ActorRegistered(who, role, pubKeyHash);
    }

    // ============================================================
    //  FUNCTION: revoke
    //  Who calls it: TA
    //  What it does: Instantly blocks an actor from the system.
    //  After revocation, isActive() returns false, so all other
    //  contracts will reject that actor's transactions.
    // ============================================================
    function revoke(
        address who,
        string memory reason
    ) public onlyTA {
        require(actors[who].isActive, "Actor not active");
        actors[who].isActive = false;
        emit ActorRevoked(who, reason);
    }

    // ============================================================
    //  FUNCTION: isActive
    //  Who calls it: SC-2, SC-3, SC-4, SC-5, SC-6 (all contracts)
    //  What it does: Simple yes/no check — is this address valid?
    //  This is the most called function in the whole system.
    // ============================================================
    function isActive(address who) public view returns (bool) {
        return actors[who].isActive;
    }

    // ============================================================
    //  FUNCTION: getRole
    //  Who calls it: Anyone, for information
    //  What it does: Returns the role string of an address
    // ============================================================
    function getRole(address who) public view returns (string memory) {
        return actors[who].role;
    }

    // ============================================================
    //  FUNCTION: transferTA
    //  Who calls it: Current TA only
    //  What it does: Passes TA authority to a new address
    //  (e.g. for key rotation or organisational handover)
    // ============================================================
    function transferTA(address newTA) public onlyTA {
        require(newTA != address(0), "Invalid address");
        trustedAuthority = newTA;
    }
}

contracts/SC2_PatientConsent.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// ============================================================
//  SC-2 · Patient Consent Manager
//  DCBA — Dual-Chain Blockchain Architecture
// ============================================================
//
//  PURPOSE:
//  This contract protects patient data sovereignty.
//  A doctor (HP) can ONLY write a medical record if the
//  patient has explicitly given them permission first.
//
//  Think of it like a time-limited "access token":
//  - Patient grants: "Doctor X can write for the next 7 days"
//  - Patient revokes: "Doctor X access is cancelled NOW"
//  - SC-3 checks: "Does this doctor currently have access?"
//
//  FLOW:
//  1. Patient calls grantAccess(doctorAddress, durationInDays)
//  2. Doctor writes prescription to SC-3
//  3. SC-3 calls hasAccess(doctorAddress, patientAddress)
//     to check the token before allowing the write
//  4. Patient can call revokeAccess(doctorAddress) anytime
//     to immediately cancel — even mid-session
//
//  No fancy encryption here — this is pure access control logic.
// ============================================================

// We need SC-1 to check that both patient and HP are registered
interface ISC1 {
    function isActive(address who) external view returns (bool);
}

contract SC2_PatientConsent {

    ISC1 public sc1;  // reference to the Identity Registry

    // ── What a consent token looks like ──────────────────────
    struct ConsentToken {
        bool    active;      // is this grant currently valid?
        uint256 grantedAt;   // when the patient granted it
        uint256 expiresAt;   // when it automatically expires
        // 0 = never expires (patient revokes manually)
    }

    // Patient address → HP address → their consent token
    // Read as: "patient X has given consent to HP Y"
    mapping(address => mapping(address => ConsentToken)) public consents;

    // ── Events ───────────────────────────────────────────────
    event AccessGranted(address indexed patient, address indexed hp, uint256 expiresAt);
    event AccessRevoked(address indexed patient, address indexed hp);

    // ── Setup ─────────────────────────────────────────────────
    constructor(address sc1Address) {
        sc1 = ISC1(sc1Address);
    }

    // ============================================================
    //  FUNCTION: grantAccess
    //  Who calls it: Patient
    //  What it does: Creates a time-limited consent token
    //  durationDays = 0 means the token never auto-expires
    //  (patient must revoke manually)
    // ============================================================
    function grantAccess(address hp, uint256 durationDays) public {
        // Both patient and HP must be registered in SC-1
        require(sc1.isActive(msg.sender), "Patient not registered in SC-1");
        require(sc1.isActive(hp),         "HP not registered in SC-1");

        uint256 expiresAt = 0;  // 0 = no expiry
        if (durationDays > 0) {
            expiresAt = block.timestamp + (durationDays * 1 days);
        }

        consents[msg.sender][hp] = ConsentToken({
            active:    true,
            grantedAt: block.timestamp,
            expiresAt: expiresAt
        });

        emit AccessGranted(msg.sender, hp, expiresAt);
    }

    // ============================================================
    //  FUNCTION: revokeAccess
    //  Who calls it: Patient
    //  What it does: Immediately cancels the HP's permission.
    //  Works even if the token has not expired yet.
    //  After this, SC-3 will reject any writes from this HP
    //  for this patient.
    // ============================================================
    function revokeAccess(address hp) public {
        require(consents[msg.sender][hp].active, "No active consent to revoke");
        consents[msg.sender][hp].active = false;
        emit AccessRevoked(msg.sender, hp);
    }

    // ============================================================
    //  FUNCTION: hasAccess
    //  Who calls it: SC-3 (before allowing a record write)
    //  What it does: Returns true if HP has valid, non-expired
    //  consent from the patient right now.
    // ============================================================
    function hasAccess(address hp, address patient) public view returns (bool) {
        ConsentToken memory token = consents[patient][hp];

        // Check 1: Was consent ever granted and not revoked?
        if (!token.active) {
            return false;
        }

        // Check 2: Has the token expired?
        // (expiresAt == 0 means it never expires)
        if (token.expiresAt != 0 && block.timestamp > token.expiresAt) {
            return false;
        }

        return true;
    }

    // ============================================================
    //  FUNCTION: getConsentInfo
    //  Who calls it: Anyone (read-only, for inspection)
    //  What it does: Returns the full details of a consent token
    // ============================================================
    function getConsentInfo(
        address patient,
        address hp
    ) public view returns (bool active, uint256 grantedAt, uint256 expiresAt) {
        ConsentToken memory t = consents[patient][hp];
        return (t.active, t.grantedAt, t.expiresAt);
    }
}

contracts/SC3_MedicalRecords.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// ============================================================
//  SC-3 · Medical Records (MBLOCK Store)
//  DCBA — Dual-Chain Blockchain Architecture
// ============================================================
//
//  PURPOSE:
//  This is where medical records (called MBLOCKs) are stored.
//  An MBLOCK is NOT the raw medical data — it is a reference
//  to encrypted data stored off-chain (e.g. IPFS).
//
//  IMPORTANT: In the real system, medical data is encrypted
//  with the patient's public key before uploading to IPFS.
//  Only the patient (with their private key) can decrypt it.
//  On-chain we only store the IPFS hash of that encrypted data.
//
//  THREE CHECKS BEFORE A RECORD IS ACCEPTED:
//  1. HP must be registered in SC-1 (Identity check)
//  2. HP must have patient's consent in SC-2 (Permission check)
//  3. The PARS score must be 0-100 (Valid range check)
//
//  After storing the record, SC-3 automatically registers
//  the prescription hash in SC-7 (oracle bridge) so that
//  SC-5 can later verify it for delivery.
//
//  DEPLOY AFTER: SC-1, SC-2, SC-7
// ============================================================

interface ISC1_v3 {
    function isActive(address who) external view returns (bool);
}
interface ISC2 {
    function hasAccess(address hp, address patient) external view returns (bool);
}
interface ISC7 {
    function registerHash(bytes32 rxHash, address hp) external;
}

contract SC3_MedicalRecords {

    ISC1_v3 public sc1;
    ISC2    public sc2;
    ISC7    public sc7;

    // ── What one medical record looks like on-chain ───────────
    struct MedicalRecord {
        address hp;            // which doctor wrote this
        address patient;       // which patient it belongs to
        string  encryptedDataHash;  // IPFS hash of encrypted MBLOCK
                               // (actual medical data is off-chain,
                               //  encrypted with patient's public key)
        uint8   parsScore;     // priority 0-100 (PARS system)
                               // 90-100 = CRITICAL, 70-89 = HIGH
                               // 40-69 = MODERATE, 0-39 = LOW
        bytes32 rxHash;        // prescription hash (sent to SC-7)
        uint256 timestamp;     // when this record was written
    }

    // Auto-incrementing record ID
    uint256 public recordCount;

    // recordId → MedicalRecord
    mapping(uint256 => MedicalRecord) public records;

    // patient address → list of their record IDs
    mapping(address => uint256[]) public patientRecords;

    // ── Events ───────────────────────────────────────────────
    event RecordAdded(
        uint256 indexed recordId,
        address indexed hp,
        address indexed patient,
        bytes32 rxHash,
        uint8   parsScore
    );

    // ── Setup ─────────────────────────────────────────────────
    constructor(address sc1Addr, address sc2Addr, address sc7Addr) {
        sc1 = ISC1_v3(sc1Addr);
        sc2 = ISC2(sc2Addr);
        sc7 = ISC7(sc7Addr);
    }

    // ============================================================
    //  FUNCTION: addRecord
    //  Who calls it: HP (Healthcare Provider / Doctor)
    //
    //  Parameters:
    //  - patient          : the patient's wallet address
    //  - encryptedDataHash: IPFS hash of the encrypted medical data
    //  - parsScore        : urgency 0-100
    //  - rxHash           : a unique hash for this prescription
    //                       (HP generates this off-chain:
    //                        e.g. keccak256 of prescription content)
    //
    //  What it does:
    //  1. Checks HP is registered
    //  2. Checks HP has patient's consent
    //  3. Stores the record
    //  4. Registers rxHash in SC-7 for delivery pipeline
    // ============================================================
    function addRecord(
        address patient,
        string  memory encryptedDataHash,
        uint8   parsScore,
        bytes32 rxHash
    ) public {
        // Check 1: HP must be registered and active
        require(sc1.isActive(msg.sender), "HP not registered in SC-1");

        // Check 2: HP must have valid patient consent
        require(
            sc2.hasAccess(msg.sender, patient),
            "No patient consent - patient must call SC2.grantAccess first"
        );

        // Check 3: PARS score must be in valid range
        require(parsScore <= 100, "PARS score must be between 0 and 100");

        // Check 4: rxHash must not be empty
        require(rxHash != bytes32(0), "rxHash cannot be empty");

        // Store the record
        recordCount++;
        records[recordCount] = MedicalRecord({
            hp:                msg.sender,
            patient:           patient,
            encryptedDataHash: encryptedDataHash,
            parsScore:         parsScore,
            rxHash:            rxHash,
            timestamp:         block.timestamp
        });

        // Add to patient's record list
        patientRecords[patient].push(recordCount);

        // Automatically register the prescription hash in SC-7
        // so SC-5 can verify it later for delivery
        sc7.registerHash(rxHash, msg.sender);

        emit RecordAdded(recordCount, msg.sender, patient, rxHash, parsScore);
    }

    // ============================================================
    //  FUNCTION: getRecord
    //  Who calls it: Patient, HP, RA (Regulatory Auditor)
    //  What it does: Returns the on-chain data for a record.
    //  Note: The actual medical content is off-chain (IPFS).
    //  This only returns the IPFS hash pointing to it.
    // ============================================================
    function getRecord(uint256 recordId) public view returns (
        address hp,
        address patient,
        string memory encryptedDataHash,
        uint8   parsScore,
        bytes32 rxHash,
        uint256 timestamp
    ) {
        MedicalRecord memory r = records[recordId];
        require(r.timestamp != 0, "Record does not exist");
        return (r.hp, r.patient, r.encryptedDataHash, r.parsScore, r.rxHash, r.timestamp);
    }

    // ============================================================
    //  FUNCTION: getPatientRecordIds
    //  Who calls it: Patient or HP (to list all records)
    //  What it does: Returns all record IDs belonging to a patient
    // ============================================================
    function getPatientRecordIds(address patient) public view returns (uint256[] memory) {
        return patientRecords[patient];
    }

    // ============================================================
    //  HELPER: getParsLabel
    //  What it does: Converts a score to a human-readable label
    // ============================================================
    function getParsLabel(uint8 score) public pure returns (string memory) {
        if (score >= 90) return "CRITICAL";
        if (score >= 70) return "HIGH";
        if (score >= 40) return "MODERATE";
        return "LOW";
    }
}

contracts/SC4_DCSScoring.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// ============================================================
//  SC-4 · DCS — Drone Capability Score
//  DCBA — Dual-Chain Blockchain Architecture
//  FIX: added sc6Address so SC6 contract can call updateReputation
// ============================================================

interface ISC1_v4 {
    function isActive(address who) external view returns (bool);
    function getRole(address who) external view returns (string memory);
}

contract SC4_DCSScoring {

    ISC1_v4 public sc1;

    // ── FIX: SC6 contract address authorized to call updateReputation ──
    address public sc6Address;

    struct UAVScore {
        address uavAddress;
        uint256 score;
        uint256 submittedAt;
        bool    verified;
    }

    struct ScoringRound {
        uint256   orderId;
        address   droneStation;
        bool      isOpen;
        address   winner;
        uint256   winnerScore;
        uint256   submissionCount;
    }

    mapping(uint256 => ScoringRound)                      public rounds;
    mapping(uint256 => mapping(address => UAVScore))       public submissions;
    mapping(uint256 => address[])                          public roundParticipants;
    mapping(address => int256)                             public reputationScore;

    uint256 public roundCount;

    event RoundOpened(uint256 indexed roundId, uint256 orderId, address droneStation);
    event ScoreSubmitted(uint256 indexed roundId, address indexed uav, uint256 score);
    event WinnerSelected(uint256 indexed roundId, address indexed winner, uint256 score);
    event ReputationUpdated(address indexed uav, int256 delta, int256 newScore);

    constructor(address sc1Addr) {
        sc1 = ISC1_v4(sc1Addr);
    }

    // ── FIX: TA calls this once after deploying SC6 ────────────────
    // This allows SC6's contract address to call updateReputation
    function linkSC6(address _sc6) public {
        require(sc6Address == address(0), "SC6 already linked");
        require(_sc6 != address(0), "Invalid address");
        sc6Address = _sc6;
    }

    function computeScore(
        uint256 speed,
        uint256 payload,
        uint256 battery,
        uint256 cpu,
        uint256 ram
    ) public pure returns (uint256) {
        require(speed <= 100 && payload <= 100 && battery <= 100, "Metrics must be 0-100");
        require(cpu <= 100 && ram <= 100, "Metrics must be 0-100");
        uint256 total = (speed * 30) + (payload * 25) + (battery * 20) + (cpu * 15) + (ram * 10);
        return total / 100;
    }

    function openRound(uint256 orderId) public returns (uint256 roundId) {
        require(sc1.isActive(msg.sender), "Caller not registered in SC-1");
        roundCount++;
        rounds[roundCount] = ScoringRound({
            orderId:         orderId,
            droneStation:    msg.sender,
            isOpen:          true,
            winner:          address(0),
            winnerScore:     0,
            submissionCount: 0
        });
        emit RoundOpened(roundCount, orderId, msg.sender);
        return roundCount;
    }

    function submitScore(uint256 roundId, uint256 score) public {
        require(sc1.isActive(msg.sender), "UAV not registered in SC-1");
        require(rounds[roundId].isOpen, "Round is closed");
        require(score <= 100, "Score must be 0-100");
        require(submissions[roundId][msg.sender].submittedAt == 0, "Already submitted");

        submissions[roundId][msg.sender] = UAVScore({
            uavAddress:  msg.sender,
            score:       score,
            submittedAt: block.timestamp,
            verified:    true
        });
        roundParticipants[roundId].push(msg.sender);
        rounds[roundId].submissionCount++;
        emit ScoreSubmitted(roundId, msg.sender, score);
    }

    function closeRound(uint256 roundId) public {
        ScoringRound storage round = rounds[roundId];
        require(msg.sender == round.droneStation, "Only the DS that opened this round");
        require(round.isOpen, "Round already closed");
        require(round.submissionCount > 0, "No scores submitted");

        address bestUAV   = address(0);
        uint256 bestScore = 0;
        address[] memory participants = roundParticipants[roundId];
        for (uint256 i = 0; i < participants.length; i++) {
            UAVScore memory s = submissions[roundId][participants[i]];
            if (s.score > bestScore) {
                bestScore = s.score;
                bestUAV   = participants[i];
            }
        }
        round.isOpen      = false;
        round.winner      = bestUAV;
        round.winnerScore = bestScore;
        emit WinnerSelected(roundId, bestUAV, bestScore);
    }

    function getWinner(uint256 roundId) public view returns (address winner, uint256 score) {
        require(!rounds[roundId].isOpen, "Round still open");
        return (rounds[roundId].winner, rounds[roundId].winnerScore);
    }

    // ── FIX: allow SC6 contract OR registered actor to call this ──
    function updateReputation(address uav, int256 delta) public {
        require(
            sc1.isActive(msg.sender) || msg.sender == sc6Address,
            "Caller not authorized (not in SC-1 and not SC6)"
        );
        reputationScore[uav] += delta;
        emit ReputationUpdated(uav, delta, reputationScore[uav]);
    }
}

contracts/SC5_DeliveryOrders.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// ============================================================
//  SC-5 · Delivery Orders (PARS Queue)
//  DCBA — Dual-Chain Blockchain Architecture
// ============================================================
//
//  PURPOSE:
//  This contract manages the delivery order queue.
//  Orders are NOT processed first-come-first-served.
//  They are processed by PRIORITY (the PARS score from SC-3).
//
//  PARS TIERS:
//  CRITICAL (90-100): Deliver within 3 minutes  — life-critical meds
//  HIGH     (70-89):  Deliver within 10 minutes — urgent meds
//  MODERATE (40-69):  Deliver within 30 minutes — routine meds
//  LOW      (0-39):   Deliver within 2 hours    — non-urgent
//
//  FLOW:
//  1. HP calls submitOrder() with the prescription hash + PARS score
//  2. SC-5 calls SC-7 to verify the prescription is real
//  3. If valid, order is stored and assigned to a Warehouse + DS
//  4. Warehouse calls confirmStock() to say drugs are ready
//  5. SC-5 emits an event → DS picks it up and runs DCS (SC-4)
//
//  DEPLOY AFTER: SC-1, SC-3, SC-7
// ============================================================

interface ISC1_v5 {
    function isActive(address who) external view returns (bool);
}
interface ISC7_v5 {
    function verifyHash(bytes32 rxHash) external returns (bool);
}

contract SC5_DeliveryOrders {

    ISC1_v5 public sc1;
    ISC7_v5 public sc7;

    // ── Order status lifecycle ────────────────────────────────
    enum OrderStatus {
        PENDING,      // submitted, waiting for stock confirmation
        CONFIRMED,    // stock confirmed, DCS running
        DISPATCHED,   // UAV picked up the package
        IN_FLIGHT,    // UAV is in the air, GPS streaming
        DELIVERED,    // patient confirmed delivery
        FAILED        // something went wrong
    }

    // ── What a delivery order looks like ─────────────────────
    struct DeliveryOrder {
        uint256     orderId;
        address     hp;           // who prescribed
        address     patient;      // who receives it
        bytes32     rxHash;       // prescription hash (verified by SC-7)
        uint8       parsScore;    // priority 0-100
        string      drugList;     // what drugs (plain text for demo)
        address     warehouse;    // which warehouse fulfils it
        address     droneStation; // which DS manages the UAV
        address     assignedUAV;  // the υpremium UAV
        OrderStatus status;
        uint256     createdAt;
        uint256     slaDeadline;  // when it must be delivered by
    }

    uint256 public orderCount;
    mapping(uint256 => DeliveryOrder) public orders;

    // patient → list of their order IDs
    mapping(address => uint256[]) public patientOrders;

    // ── Events ───────────────────────────────────────────────
    event OrderSubmitted(uint256 indexed orderId, address indexed patient, uint8 parsScore, bytes32 rxHash);
    event StockConfirmed(uint256 indexed orderId, address warehouse);
    event UAVAssigned(uint256 indexed orderId, address uav);
    event OrderStatusUpdated(uint256 indexed orderId, OrderStatus newStatus);

    // ── Setup ─────────────────────────────────────────────────
    constructor(address sc1Addr, address sc7Addr) {
        sc1 = ISC1_v5(sc1Addr);
        sc7 = ISC7_v5(sc7Addr);
    }

    // ============================================================
    //  FUNCTION: submitOrder
    //  Who calls it: HP (Healthcare Provider)
    //
    //  Parameters:
    //  - patient      : patient's wallet address
    //  - rxHash       : the prescription hash from SC-3
    //  - parsScore    : urgency (0-100), same as in SC-3
    //  - drugList     : plain text list of drugs
    //  - warehouse    : address of the drug warehouse to use
    //  - droneStation : address of the drone station to use
    //
    //  What it does:
    //  1. Verifies HP is registered
    //  2. Asks SC-7: is this prescription real and unused?
    //  3. If yes, creates the order with SLA deadline
    //  4. SLA deadline = now + (time based on PARS tier)
    // ============================================================
    function submitOrder(
        address patient,
        bytes32 rxHash,
        uint8   parsScore,
        string  memory drugList,
        address warehouse,
        address droneStation
    ) public returns (uint256) {
        require(sc1.isActive(msg.sender), "HP not registered");
        require(sc1.isActive(patient),    "Patient not registered");
        require(sc1.isActive(warehouse),  "Warehouse not registered");
        require(sc1.isActive(droneStation), "Drone station not registered");
        require(parsScore <= 100,         "PARS score out of range");

        // Ask SC-7: is this prescription valid?
        bool isValid = sc7.verifyHash(rxHash);
        require(isValid, "Prescription not verified by SC-7 oracle");

        // Calculate SLA deadline based on PARS score
        uint256 sla = getSLASeconds(parsScore);

        orderCount++;
        orders[orderCount] = DeliveryOrder({
            orderId:      orderCount,
            hp:           msg.sender,
            patient:      patient,
            rxHash:       rxHash,
            parsScore:    parsScore,
            drugList:     drugList,
            warehouse:    warehouse,
            droneStation: droneStation,
            assignedUAV:  address(0),  // assigned after DCS
            status:       OrderStatus.PENDING,
            createdAt:    block.timestamp,
            slaDeadline:  block.timestamp + sla
        });

        patientOrders[patient].push(orderCount);

        emit OrderSubmitted(orderCount, patient, parsScore, rxHash);
        return orderCount;
    }

    // ============================================================
    //  FUNCTION: confirmStock
    //  Who calls it: Drug Warehouse (DW)
    //  What it does: Warehouse says "yes, drugs are available"
    //  Moves order from PENDING → CONFIRMED
    // ============================================================
    function confirmStock(uint256 orderId) public {
        DeliveryOrder storage order = orders[orderId];
        require(msg.sender == order.warehouse, "Only the assigned warehouse");
        require(order.status == OrderStatus.PENDING, "Order not in PENDING state");

        order.status = OrderStatus.CONFIRMED;
        emit StockConfirmed(orderId, msg.sender);
        emit OrderStatusUpdated(orderId, OrderStatus.CONFIRMED);
    }

    // ============================================================
    //  FUNCTION: assignUAV
    //  Who calls it: Drone Station (DS) after SC-4 picks winner
    //  What it does: Records which UAV won the DCS round
    //  Moves order to DISPATCHED
    // ============================================================
    function assignUAV(uint256 orderId, address uav) public {
        DeliveryOrder storage order = orders[orderId];
        require(msg.sender == order.droneStation, "Only the assigned drone station");
        require(order.status == OrderStatus.CONFIRMED, "Order not CONFIRMED yet");
        require(sc1.isActive(uav), "UAV not registered");

        order.assignedUAV = uav;
        order.status      = OrderStatus.DISPATCHED;

        emit UAVAssigned(orderId, uav);
        emit OrderStatusUpdated(orderId, OrderStatus.DISPATCHED);
    }

    // ============================================================
    //  FUNCTION: updateStatus
    //  Who calls it: DS or UAV (to move through lifecycle states)
    //  What it does: Advances the order to the next status
    //  SC-6 also calls this internally.
    // ============================================================
    function updateStatus(uint256 orderId, OrderStatus newStatus) public {
        require(sc1.isActive(msg.sender), "Caller not registered");
        DeliveryOrder storage order = orders[orderId];

        // Basic checks — DS or assigned UAV can update
        require(
            msg.sender == order.droneStation || msg.sender == order.assignedUAV,
            "Only DS or assigned UAV can update status"
        );

        order.status = newStatus;
        emit OrderStatusUpdated(orderId, newStatus);
    }

    // ============================================================
    //  FUNCTION: getOrder
    //  Who calls it: Anyone (read-only)
    // ============================================================
    function getOrder(uint256 orderId) public view returns (
        address hp,
        address patient,
        uint8   parsScore,
        string  memory drugList,
        address assignedUAV,
        OrderStatus status,
        uint256 slaDeadline
    ) {
        DeliveryOrder memory o = orders[orderId];
        return (o.hp, o.patient, o.parsScore, o.drugList, o.assignedUAV, o.status, o.slaDeadline);
    }

    // ============================================================
    //  HELPER: getSLASeconds
    //  What it does: Converts PARS score to SLA deadline in seconds
    // ============================================================
    function getSLASeconds(uint8 parsScore) public pure returns (uint256) {
        if (parsScore >= 90) return 3  * 60;          // CRITICAL: 3 minutes
        if (parsScore >= 70) return 10 * 60;          // HIGH:     10 minutes
        if (parsScore >= 40) return 30 * 60;          // MODERATE: 30 minutes
        return                      2  * 60 * 60;     // LOW:      2 hours
    }

    // ============================================================
    //  HELPER: getParsLabel (same as SC-3, repeated for convenience)
    // ============================================================
    function getParsLabel(uint8 score) public pure returns (string memory) {
        if (score >= 90) return "CRITICAL - 3min SLA";
        if (score >= 70) return "HIGH - 10min SLA";
        if (score >= 40) return "MODERATE - 30min SLA";
        return "LOW - 2hr SLA";
    }
}

contracts/SC6_DeliveryLifecycle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// ============================================================
//  SC-6 · Delivery Lifecycle Manager
//  DCBA — Dual-Chain Blockchain Architecture
// ============================================================
//
//  PURPOSE:
//  This contract tracks the real-world delivery journey
//  from warehouse pickup to patient doorstep.
//
//  STATE MACHINE:
//  PENDING → CONFIRMED → DISPATCHED → IN_FLIGHT → DELIVERED
//                                        ↓ (if problem)
//                                    DEVIATED (re-dispatch)
//
//  KEY FEATURES:
//  1. GPS Logging: UAV submits an IPFS hash every ~1 second
//     during IN_FLIGHT. Each hash points to a GPS coordinate
//     stored off-chain on IPFS. This creates a tamper-proof
//     location trail that RA can audit.
//
//  2. Deviation Detection: DS flags a route anomaly.
//     The order goes to DEVIATED state and needs re-dispatch.
//
//  3. Delivery Confirmation: Patient confirms delivery by
//     providing a simple signature (their address + orderId).
//     This triggers the reputation update in SC-4.
//
//  DEPLOY AFTER: SC-1, SC-4, SC-5
// ============================================================

interface ISC1_v6 {
    function isActive(address who) external view returns (bool);
}
interface ISC4 {
    function updateReputation(address uav, int256 delta) external;
}

contract SC6_DeliveryLifecycle {

    ISC1_v6 public sc1;
    ISC4    public sc4;

    // ── Delivery status (mirrors SC-5 for standalone tracking) ─
    enum DeliveryStatus {
        PENDING,      // 0
        CONFIRMED,    // 1
        DISPATCHED,   // 2
        IN_FLIGHT,    // 3
        DELIVERED,    // 4
        DEVIATED,     // 5 — route anomaly, needs re-dispatch
        FAILED        // 6
    }

    // ── Main delivery tracking record ────────────────────────
    struct Delivery {
        uint256 orderId;
        address assignedUAV;
        address patient;
        address droneStation;
        DeliveryStatus status;
        uint256 startedAt;        // when UAV took off
        uint256 deliveredAt;      // when patient confirmed
        bool    withinSLA;        // was SLA met?
        uint256 slaDeadline;
        uint256 gpsUpdateCount;   // how many GPS logs received
    }

    // ── GPS log entry ─────────────────────────────────────────
    // In real system: UAV uploads GPS coordinates to IPFS,
    // gets back an IPFS content hash, submits that hash here.
    struct GPSLog {
        string  ipfsHash;    // IPFS hash pointing to the GPS data
        uint256 timestamp;
    }

    // orderId → Delivery
    mapping(uint256 => Delivery) public deliveries;

    // orderId → list of GPS logs
    mapping(uint256 => GPSLog[]) public gpsLogs;

    // orderId → whether deviation was flagged
    mapping(uint256 => bool) public deviationFlagged;

    // ── Events ───────────────────────────────────────────────
    event DeliveryCreated(uint256 indexed orderId, address indexed uav, address indexed patient);
    event StatusUpdated(uint256 indexed orderId, DeliveryStatus newStatus);
    event GPSUpdated(uint256 indexed orderId, string ipfsHash, uint256 timestamp);
    event DeviationFlagged(uint256 indexed orderId, address droneStation, string reason);
    event DeliveryConfirmed(uint256 indexed orderId, address patient, bool withinSLA);

    // ── Setup ─────────────────────────────────────────────────
    constructor(address sc1Addr, address sc4Addr) {
        sc1 = ISC1_v6(sc1Addr);
        sc4 = ISC4(sc4Addr);
    }

    // ============================================================
    //  FUNCTION: createDelivery
    //  Who calls it: Drone Station (DS) after UAV is assigned
    //  What it does: Sets up the tracking record for this delivery
    // ============================================================
    function createDelivery(
        uint256 orderId,
        address uav,
        address patient,
        uint256 slaDeadline
    ) public {
        require(sc1.isActive(msg.sender), "DS not registered");
        require(sc1.isActive(uav),        "UAV not registered");
        require(deliveries[orderId].startedAt == 0, "Delivery already created");

        deliveries[orderId] = Delivery({
            orderId:        orderId,
            assignedUAV:    uav,
            patient:        patient,
            droneStation:   msg.sender,
            status:         DeliveryStatus.DISPATCHED,
            startedAt:      block.timestamp,
            deliveredAt:    0,
            withinSLA:      false,
            slaDeadline:    slaDeadline,
            gpsUpdateCount: 0
        });

        emit DeliveryCreated(orderId, uav, patient);
        emit StatusUpdated(orderId, DeliveryStatus.DISPATCHED);
    }

    // ============================================================
    //  FUNCTION: setInFlight
    //  Who calls it: UAV (when it takes off)
    //  What it does: Marks delivery as IN_FLIGHT, GPS logging begins
    // ============================================================
    function setInFlight(uint256 orderId) public {
        Delivery storage d = deliveries[orderId];
        require(msg.sender == d.assignedUAV, "Only the assigned UAV");
        require(d.status == DeliveryStatus.DISPATCHED, "Not in DISPATCHED state");

        d.status = DeliveryStatus.IN_FLIGHT;
        emit StatusUpdated(orderId, DeliveryStatus.IN_FLIGHT);
    }

    // ============================================================
    //  FUNCTION: logGPS
    //  Who calls it: UAV (every ~1 second during IN_FLIGHT)
    //
    //  Parameters:
    //  - orderId  : which delivery this GPS log belongs to
    //  - ipfsHash : IPFS content hash of the GPS data
    //               (off-chain: UAV uploads coordinates to IPFS,
    //                gets this hash back, then calls this function)
    //
    //  What it does: Appends an IPFS hash to the GPS trail.
    //  This creates an immutable, tamper-evident location record.
    // ============================================================
    function logGPS(uint256 orderId, string memory ipfsHash) public {
        Delivery storage d = deliveries[orderId];
        require(msg.sender == d.assignedUAV, "Only assigned UAV can log GPS");
        require(d.status == DeliveryStatus.IN_FLIGHT, "UAV not in flight");

        gpsLogs[orderId].push(GPSLog({
            ipfsHash:  ipfsHash,
            timestamp: block.timestamp
        }));

        d.gpsUpdateCount++;
        emit GPSUpdated(orderId, ipfsHash, block.timestamp);
    }

    // ============================================================
    //  FUNCTION: flagDeviation
    //  Who calls it: Drone Station (DS) monitoring the GPS feed
    //  What it does: Marks the delivery as deviated.
    //  The DS can then trigger a new DCS round (SC-4) to
    //  assign a replacement UAV.
    // ============================================================
    function flagDeviation(uint256 orderId, string memory reason) public {
        Delivery storage d = deliveries[orderId];
        require(msg.sender == d.droneStation, "Only assigned DS");
        require(d.status == DeliveryStatus.IN_FLIGHT, "UAV not in flight");

        d.status = DeliveryStatus.DEVIATED;
        deviationFlagged[orderId] = true;

        // Penalise the UAV reputation for deviating
        sc4.updateReputation(d.assignedUAV, -10);

        emit DeviationFlagged(orderId, msg.sender, reason);
        emit StatusUpdated(orderId, DeliveryStatus.DEVIATED);
    }

    // ============================================================
    //  FUNCTION: confirmDelivery
    //  Who calls it: Patient (when they physically receive the drugs)
    //  What it does:
    //  1. Marks delivery as DELIVERED
    //  2. Checks if SLA was met
    //  3. Updates UAV reputation in SC-4:
    //     +5 if on time, -5 if late
    // ============================================================
    function confirmDelivery(uint256 orderId) public {
        Delivery storage d = deliveries[orderId];
        require(msg.sender == d.patient, "Only the patient can confirm delivery");
        require(d.status == DeliveryStatus.IN_FLIGHT || d.status == DeliveryStatus.DISPATCHED,
                "Delivery not in progress");

        d.status      = DeliveryStatus.DELIVERED;
        d.deliveredAt = block.timestamp;

        // Was SLA met?
        bool onTime = (block.timestamp <= d.slaDeadline);
        d.withinSLA = onTime;

        // Update UAV reputation
        if (onTime) {
            sc4.updateReputation(d.assignedUAV, 5);   // on-time bonus
        } else {
            sc4.updateReputation(d.assignedUAV, -5);  // late penalty
        }

        emit DeliveryConfirmed(orderId, msg.sender, onTime);
        emit StatusUpdated(orderId, DeliveryStatus.DELIVERED);
    }

    // ============================================================
    //  FUNCTION: getDeliveryStatus
    //  Who calls it: Anyone (read-only)
    // ============================================================
    function getDeliveryStatus(uint256 orderId) public view returns (
        DeliveryStatus status,
        address uav,
        uint256 gpsUpdateCount,
        bool    withinSLA,
        bool    deviated
    ) {
        Delivery memory d = deliveries[orderId];
        return (d.status, d.assignedUAV, d.gpsUpdateCount, d.withinSLA, deviationFlagged[orderId]);
    }

    // ============================================================
    //  FUNCTION: getGPSLog
    //  Who calls it: RA (Regulatory Auditor) for audit
    //  What it does: Returns the full GPS trail for a delivery
    //  (list of IPFS hashes + timestamps)
    // ============================================================
    function getGPSLog(uint256 orderId) public view returns (
        string[] memory hashes,
        uint256[] memory timestamps
    ) {
        GPSLog[] memory logs = gpsLogs[orderId];
        string[]  memory h = new string[](logs.length);
        uint256[] memory t = new uint256[](logs.length);

        for (uint256 i = 0; i < logs.length; i++) {
            h[i] = logs[i].ipfsHash;
            t[i] = logs[i].timestamp;
        }
        return (h, t);
    }
}

contracts/SC7_OracleBridge.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// ============================================================
//  SC-7 · Cross-Chain Oracle Bridge
//  DCBA — Dual-Chain Blockchain Architecture
// ============================================================
//
//  PURPOSE:
//  This contract is the "bridge" between the two chains.
//  In the real system, SC-3 lives on PDC (Patient Data Chain)
//  and SC-5 lives on UOC (UAV Operational Chain).
//
//  For Remix/testnet demo, both live on one chain, but this
//  contract still plays the role of the oracle:
//
//  FLOW:
//  1. When a doctor writes a prescription (SC-3), the
//     prescription hash (rxHash) is registered here.
//  2. When a delivery order is submitted (SC-5), SC-7 is
//     asked: "Is this prescription real and unused?"
//  3. SC-7 returns true (VALID) or false (INVALID/EXPIRED).
//  4. Each rxHash can only be verified ONCE — this prevents
//     someone from reusing the same prescription twice.
//     (This is called "replay attack prevention".)
//
//  DEPLOY ORDER: Deploy SC-7 right after SC-1.
// ============================================================

contract SC7_OracleBridge {

    // ── Who controls this oracle ──────────────────────────────
    address public trustedAuthority;  // same TA as SC-1
    address public sc3Address;        // SC-3 is the only one allowed
                                      // to register new hashes

    // ── The status of each prescription hash ─────────────────
    // A prescription hash starts as PENDING (not registered),
    // becomes VALID when SC-3 registers it,
    // and becomes USED once SC-5 verifies it (one-time use).
    enum HashStatus { PENDING, VALID, USED }

    struct PrescriptionRecord {
        HashStatus status;
        uint256    registeredAt;   // when SC-3 added it
        uint256    usedAt;         // when SC-5 consumed it (0 if not yet)
        address    registeredBy;   // which HP address registered it
    }

    // rxHash → its record
    mapping(bytes32 => PrescriptionRecord) public prescriptions;

    // ── Events ───────────────────────────────────────────────
    event HashRegistered(bytes32 indexed rxHash, address indexed hp);
    event HashVerified(bytes32 indexed rxHash, bool valid);

    // ── Setup ─────────────────────────────────────────────────
    constructor() {
        trustedAuthority = msg.sender;
    }

    modifier onlyTA() {
        require(msg.sender == trustedAuthority, "Only TA");
        _;
    }

    // ── Link SC-3 after deployment ────────────────────────────
    // TA calls this once after deploying SC-3, to tell SC-7
    // the address of SC-3 (so only SC-3 can register hashes).
    function setSC3Address(address _sc3) public onlyTA {
        sc3Address = _sc3;
    }

    // ============================================================
    //  FUNCTION: registerHash
    //  Who calls it: SC-3 (automatically when a record is added)
    //  What it does: Marks a prescription hash as VALID so it
    //  can later be verified by SC-5 for delivery.
    // ============================================================
    function registerHash(bytes32 rxHash, address hp) public {
        require(msg.sender == sc3Address, "Only SC-3 can register");
        require(
            prescriptions[rxHash].status == HashStatus.PENDING,
            "Hash already registered"
        );

        prescriptions[rxHash] = PrescriptionRecord({
            status:       HashStatus.VALID,
            registeredAt: block.timestamp,
            usedAt:       0,
            registeredBy: hp
        });

        emit HashRegistered(rxHash, hp);
    }

    // ============================================================
    //  FUNCTION: verifyHash
    //  Who calls it: SC-5 (when HP submits a delivery order)
    //  What it does:
    //    - Returns true  if hash is VALID (prescription is real)
    //    - Returns false if hash is PENDING (never registered)
    //    - Returns false if hash is USED   (already delivered once)
    //  The hash is then marked as USED so it cannot be reused.
    //  This is the replay attack prevention.
    // ============================================================
    function verifyHash(bytes32 rxHash) public returns (bool) {
        // Only SC-5 should call this in the full system.
        // For testnet demo, we allow any registered caller.
        PrescriptionRecord storage rec = prescriptions[rxHash];

        if (rec.status != HashStatus.VALID) {
            emit HashVerified(rxHash, false);
            return false;
        }

        // Mark as USED — cannot be verified again
        rec.status = HashStatus.USED;
        rec.usedAt = block.timestamp;

        emit HashVerified(rxHash, true);
        return true;
    }

    // ============================================================
    //  FUNCTION: checkHash  (read-only, no state change)
    //  Who calls it: Anyone wanting to see the current status
    //  Returns: 0=PENDING, 1=VALID, 2=USED
    // ============================================================
    function checkHash(bytes32 rxHash) public view returns (uint8) {
        return uint8(prescriptions[rxHash].status);
    }
}

